// 2026-05-08 (env audit): validators de configuração no boot.
// (a) Whitespace em nomes de env (Railway permite, mas process.env.X retorna
//     undefined porque o name real é 'X    '). Bot usa default em código,
//     comportamento silenciosamente errado.
// (b) KELLY hierarchy: ALTA confidence deveria stake >= MEDIA >= BAIXA.
//     Inversão = bug de config (visto: KELLY_CS_ALTA=0.212 < MEDIA=0.30).
// (c) Envs spurious typo (FOOTBALLMTSHADOWONLY, VAL_MARKET_TIPS_ENABLED, etc).
// Warns no boot — admin pode corrigir no Railway.
try {
  const envKeys = Object.keys(process.env);
  // (a) whitespace
  const wsKeys = envKeys.filter(k => /\s/.test(k));
  if (wsKeys.length) {
    for (const k of wsKeys) {
      log('WARN', 'ENV-AUDIT', `whitespace em nome de env: '${k}' (process.env['${k.trim()}'] retorna undefined → bot usa default)`);
    }
  }
  // (b) KELLY hierarchy
  const sports = ['LOL', 'CS', 'CS2', 'DOTA2', 'TENNIS', 'VALORANT', 'FOOTBALL', 'MMA', 'BASKET'];
  for (const sp of sports) {
    const baixa = parseFloat(process.env[`KELLY_${sp}_BAIXA`]);
    const media = parseFloat(process.env[`KELLY_${sp}_MEDIA`]);
    const alta = parseFloat(process.env[`KELLY_${sp}_ALTA`]);
    if (Number.isFinite(media) && Number.isFinite(alta) && alta < media) {
      log('WARN', 'ENV-AUDIT', `KELLY_${sp}_ALTA=${alta} < KELLY_${sp}_MEDIA=${media} (inversão lógica — ALTA confidence deveria stake mais)`);
    }
    if (Number.isFinite(baixa) && Number.isFinite(media) && media < baixa) {
      log('WARN', 'ENV-AUDIT', `KELLY_${sp}_MEDIA=${media} < KELLY_${sp}_BAIXA=${baixa} (inversão lógica)`);
    }
  }
  // (c) typos conhecidos — match envs sem underscore que código procura com underscore
  const typoMap = {
    'FOOTBALLMTSHADOWONLY': 'FOOTBALL_MT_SHADOW_ONLY',
    'FOOTBALLMAXDIVERGENCEPP': 'FB_DIVERGENCE_MAX_PP',
    'VAL_MARKET_TIPS_ENABLED': 'VALORANT_MARKET_TIPS_ENABLED',
  };
  for (const [typo, correct] of Object.entries(typoMap)) {
    if (process.env[typo] !== undefined) {
      log('WARN', 'ENV-AUDIT', `env spurious '${typo}' setada — código lê '${correct}'. Renomeie ou delete.`);
    }
  }
} catch (e) { log('DEBUG', 'ENV-AUDIT', `validator falhou: ${e.message}`); }

// Filtra candidates odds pra manter só books que user aposta.
// ENV: PREFERRED_BOOKMAKERS=Pinnacle,Bet365 (csv, case-insensitive, substring match).
// Fallback: se nenhum candidate bate (ex: SX.Bet é único disponível), retorna
// todos os candidates (better than no tip).
function _filterPreferredBooks(candidates) {
  const raw = process.env.PREFERRED_BOOKMAKERS;
  if (!raw || !candidates?.length) return candidates;
  const allowed = raw.split(',').map(s => s.trim().toLowerCase()).filter(Boolean);
  if (!allowed.length) return candidates;
  const filtered = candidates.filter(c => {
    const book = String(c?.bookmaker || '').toLowerCase();
    return allowed.some(a => book.includes(a) || a.includes(book));
  });
  return filtered.length ? filtered : candidates;
}

// PandaScore /matches/{id} response → "Bo3 2-1" string pra match_results.final_score.
// Sem isso, _parseEsportsMapScore não tem dado pra liquidar handicap/total esports.
// Retorna '' se faltam campos essenciais — caller mantém row sem score (settle vai skip).
function _psSeriesScore(m) {
  const t1Id = m?.opponents?.[0]?.opponent?.id;
  const t2Id = m?.opponents?.[1]?.opponent?.id;
  const results = Array.isArray(m?.results) ? m.results : [];
  if (!t1Id || !t2Id || results.length < 2) return '';
  const r1 = results.find(x => x.team_id === t1Id)?.score;
  const r2 = results.find(x => x.team_id === t2Id)?.score;
  if (!Number.isFinite(r1) || !Number.isFinite(r2)) return '';
  const bo = Number.isFinite(m?.number_of_games) ? m.number_of_games : null;
  return bo ? `Bo${bo} ${r1}-${r2}` : `${r1}-${r2}`;
}

function getBaseline() {
  const rows = db.prepare("SELECT key, value FROM settings WHERE key IN ('bankroll_baseline_date','bankroll_baseline_amount','bankroll_unit_pct')").all();
  const map = Object.fromEntries(rows.map(r => [r.key, r.value]));
  const amount = parseFloat(map.bankroll_baseline_amount) || 900;
  const pct = parseFloat(map.bankroll_unit_pct) || 1.0;
  // Per-sport tier model (Abr/2026-III): 1u = R$1 base por sport, independente do baseline.
  // Fórmula legada `amount * pct / 100` dava 10 pra baseline 1000, inflando fallback
  // recomputes em queries que não selecionam stake_reais/profit_reais stored.
  return {
    date: map.bankroll_baseline_date || '2026-04-16',
    amount,
    unit_pct: pct,
    unit_value: 1.0,
  };
}

// Unit-native recompute: stake em u × unit_value atual. DB guarda snapshots (stake_reais/
// profit_reais) calculados no momento do settlement com unit_value daquela época; se
// baseline mudar, recomputamos on-the-fly pra consistência.
// Pós modelo per-sport unit (Abr/2026-III): prefere stake_reais/profit_reais stored
// (rebuild pelo migration 040 com tier unit per-sport). Fallback recompute só se null.
//
// 2026-05-05: pra PENDING tips (stake_reais NULL), recompute com per-sport tier unit
// (mesmo cálculo do Telegram formatStakeWithReais). Antes usava global baseline=1.0
// → divergência: Telegram tennis ratio 0.76 = R$0.80/u, dashboard = R$1.00/u →
// stake 1.25u era R$1.00 no TG e R$1.25 no dashboard.
const _bankrollUvCache = new Map(); // sport → { uv, ts }
const _BANKROLL_UV_TTL = 60000; // 1min
function _getSportUnitForTip(sportKey) {
  if (!sportKey) return 1.0;
  const now = Date.now();
  const c = _bankrollUvCache.get(sportKey);
  if (c && (now - c.ts) < _BANKROLL_UV_TTL) return c.uv;
  try {
    const bk = db.prepare('SELECT initial_banca, current_banca FROM bankroll WHERE sport=?').get(sportKey);
    if (!bk) { _bankrollUvCache.set(sportKey, { uv: 1.0, ts: now }); return 1.0; }
    const { getSportUnitValue } = require('./lib/sport-unit');
    const uv = getSportUnitValue(bk.current_banca || 0, bk.initial_banca || 100);
    _bankrollUvCache.set(sportKey, { uv, ts: now });
    return uv;
  } catch (_) { return 1.0; }
}
function tipStakeReais(tip, unitValue) {
  if (tip.stake_reais != null) {
    const stored = Number(tip.stake_reais);
    if (Number.isFinite(stored)) return stored;
  }
  const stakeU = parseFloat(String(tip.stake || '').replace(/u/i, '')) || 0;
  // Per-sport tier unit p/ pending tips (alinha com Telegram). Fallback unitValue
  // mantido pra compat de callers que querem override explícito.
  const uvSport = tip.sport ? _getSportUnitForTip(tip.sport) : (unitValue || 1);
  const uv = unitValue && unitValue !== 1.0 ? unitValue : uvSport;
  return +(stakeU * uv).toFixed(2);
}
function tipProfitReais(tip, unitValue) {
  if (tip.profit_reais != null) {
    const stored = Number(tip.profit_reais);
    if (Number.isFinite(stored)) return stored;
  }
  const stakeU = parseFloat(String(tip.stake || '').replace(/u/i, '')) || 0;
  const odds = parseFloat(tip.odds) || 1;
  const uvSport = tip.sport ? _getSportUnitForTip(tip.sport) : (unitValue || 1);
  const uv = unitValue && unitValue !== 1.0 ? unitValue : uvSport;
  if (!stakeU || !uv || uv <= 0) return null;
  if (tip.result === 'win')  return +((stakeU * (odds - 1) * uv)).toFixed(2);
  if (tip.result === 'loss') return +(-(stakeU * uv)).toFixed(2);
  if (tip.result === 'push' || tip.result === 'void') return 0;
  return null;
}

// ── Football Elo helper (1X2) ──
function getElo(team) {
  const row = stmts.getFootballElo.get(team);
  return row?.rating ? parseFloat(row.rating) : 1500;
}
function getEloGames(team) {
  const row = stmts.getFootballElo.get(team);
  return row?.games ? parseInt(row.games, 10) : 0;
}
function expectedScore(rA, rB) {
  return 1 / (1 + Math.pow(10, (rB - rA) / 400));
}
function updateEloMatch(homeTeam, awayTeam, winner) {
  const K = parseFloat(process.env.FOOTBALL_ELO_K || '20') || 20;
  const homeAdvElo = parseFloat(process.env.FOOTBALL_ELO_HOME_ADV || '50') || 50; // ~6–8pp
  const rH = getElo(homeTeam);
  const rA = getElo(awayTeam);
  const eH = expectedScore(rH + homeAdvElo, rA);
  const eA = 1 - eH;

  const sH = (winner === homeTeam) ? 1 : (winner === 'Draw' ? 0.5 : 0);
  const sA = 1 - sH;

  const newH = rH + K * (sH - eH);
  const newA = rA + K * (sA - eA);

  const gH = getEloGames(homeTeam) + 1;
  const gA = getEloGames(awayTeam) + 1;
  stmts.upsertFootballElo.run(homeTeam, newH, gH);
  stmts.upsertFootballElo.run(awayTeam, newA, gA);
  return { homeTeam, awayTeam, before: { rH, rA }, after: { newH, newA }, K, homeAdvElo };
}

/** Escopo SQL: uma linha por partida; evita duplicatas de match_id no dashboard/ROI.
 * Também filtra archived=0 pra esconder tips contaminadas (pré 2026-04-17, bugs de dedup/Kelly).
 * 2026-05-24 audit (dashboard fix 13ad1ff): priority dedup — win/loss/push > null > void.
 * Antes MAX(id) puro fazia void mascara loss settled (caso real Kostyuk #4063 vs #4176). */
function sqlTipsDedupeIdIn(alias, sportParam = '?') {
  return `${alias}.id IN (SELECT COALESCE(
    MAX(CASE WHEN tdx.result IN ('win','loss','push') THEN tdx.id END),
    MAX(CASE WHEN tdx.result IS NULL THEN tdx.id END),
    MAX(tdx.id)
  ) FROM tips tdx WHERE tdx.sport = ${sportParam} AND (tdx.archived IS NULL OR tdx.archived = 0) GROUP BY COALESCE(NULLIF(TRIM(tdx.match_id), ''), 'id:' || CAST(tdx.id AS TEXT)))`;
}

/** Filtro simples pra queries que não usam dedupe mas precisam excluir tips arquivadas. */
function sqlNotArchived(alias) {
  return `(${alias}.archived IS NULL OR ${alias}.archived = 0)`;
}

const { rollupLeague } = require('./lib/league-rollup');

/**
 * Sub-game filter p/ esportes "guarda-chuva" (esports=lol/dota, mma=mma/boxing).
 * Retorna '' se não se aplica — seguro para concatenar em qualquer WHERE.
 */
function sqlGameFilter(alias, sport, game) {
  if (!game) return '';
  const g = String(game).toLowerCase();
  if (sport === 'esports' || sport === 'lol' || sport === 'dota2' || sport === 'dota') {
    // Dota: match_id 'dota2_%' (PandaScore) OU event_name contém 'dota' (Pinnacle 'pin_*' não tem prefixo).
    // Bug fix 2026-04-18: tips Dota via Pinnacle (pin_*) eram contadas como LoL.
    if (g === 'dota2' || g === 'dota') {
      return ` AND (${alias}.match_id LIKE 'dota2_%' OR LOWER(COALESCE(${alias}.event_name,'')) LIKE '%dota%')`;
    }
    if (g === 'lol') {
      return ` AND ${alias}.match_id NOT LIKE 'dota2_%' AND LOWER(COALESCE(${alias}.event_name,'')) NOT LIKE '%dota%'`;
    }
  }
  if (sport === 'mma') {
    if (g === 'boxing' || g === 'boxe') return ` AND LOWER(COALESCE(${alias}.event_name,'')) LIKE '%boxing%'`;
    if (g === 'mma')                    return ` AND LOWER(COALESCE(${alias}.event_name,'')) NOT LIKE '%boxing%'`;
  }
  return '';
}

/**
 * Pós-split LoL/Dota: mapeia sport+game pro set de sport tags a querying union.
 * Cobre legado ('esports' bucket) + novos ('lol', 'dota2').
 *   sport='lol' → ['esports','lol'] + sqlGameFilter(game='lol') vai aplicar NOT LIKE 'dota2_%'.
 *   sport='dota2' → ['esports','dota2'] + sqlGameFilter(game='dota2') aplica LIKE 'dota2_%'.
 *   sport='esports' + game='lol' → ['esports','lol'] (compat com dropdown antigo).
 *   sport='esports' sem game → ['esports','lol','dota2'] (view combinada).
 *   outros sports → [sport] (trivial).
 * Retorna { sportSet, effectiveGame } — effectiveGame é injetado pra sqlGameFilter filtrar
 * tips legadas 'esports' por match_id quando sport='lol'/'dota2' é solicitado.
 */
function resolveSportSet(sport, game) {
  const s = String(sport || '').toLowerCase();
  const g = String(game || '').toLowerCase();
  if (s === 'lol') return { sportSet: ['esports', 'lol'], effectiveGame: 'lol' };
  if (s === 'dota2' || s === 'dota') return { sportSet: ['esports', 'dota2'], effectiveGame: 'dota2' };
  if (s === 'esports') {
    if (g === 'lol') return { sportSet: ['esports', 'lol'], effectiveGame: 'lol' };
    if (g === 'dota' || g === 'dota2') return { sportSet: ['esports', 'dota2'], effectiveGame: 'dota2' };
    return { sportSet: ['esports', 'lol', 'dota2'], effectiveGame: '' };
  }
  return { sportSet: [s], effectiveGame: g };
}

// ── Import dataset CSV (football matches 2024/2025) ──
function parseCsvRows(text) {
  const rows = [];
  let i = 0;
  let field = '';
  let row = [];
  let inQuotes = false;
  while (i < text.length) {
    const ch = text[i];
    if (inQuotes) {
      if (ch === '"') {
        const next = text[i + 1];
        if (next === '"') { field += '"'; i += 2; continue; }
        inQuotes = false;
        i++;
        continue;
      }
      field += ch;
      i++;
      continue;
    }
    if (ch === '"') { inQuotes = true; i++; continue; }
    if (ch === ',') { row.push(field); field = ''; i++; continue; }
    if (ch === '\r') { i++; continue; }
    if (ch === '\n') {
      row.push(field);
      rows.push(row);
      row = [];
      field = '';
      i++;
      continue;
    }
    field += ch;
    i++;
  }
  if (field.length || row.length) {
    row.push(field);
    rows.push(row);
  }
  return rows;
}

function idxOf(headers, name) {
  const n = String(name || '').toLowerCase().trim();
  return headers.findIndex(h => String(h || '').toLowerCase().trim() === n);
}

async function importFootballMatchesCsvOnce() {
  const enabled = (process.env.FOOTBALL_DATASET_IMPORT ?? 'true') !== 'false';
  if (!enabled) return;
  const urlCsv = process.env.FOOTBALL_MATCHES_CSV_URL
    || 'https://raw.githubusercontent.com/tarekmasryo/Football-Matches-Results-2024-25-Dataset/main/data/football_matches_2024_2025.csv';
  const key = `football_matches_csv:${urlCsv}`;
  const exists = stmts.getDatasetImport.get(key);
  if (exists) return;

  try {
    const r = await cachedHttpGet(urlCsv, { provider: 'football_dataset', ttlMs: 24 * 60 * 60 * 1000 }).catch(() => null);
    if (!r || r.status !== 200) { log('WARN', 'IMPORT', `CSV football: HTTP ${r?.status || 'fail'}`); return; }
    const rows = parseCsvRows(String(r.body || ''));
    if (!rows.length || rows.length < 2) { log('WARN', 'IMPORT', 'CSV football: vazio'); return; }

    const headers = rows[0];
    const c = {
      // formato "tarekmasryo" antigo (planejado)
      competition_name: idxOf(headers, 'competition_name'),
      utc_date: idxOf(headers, 'utc_date'),
      home_team_name: idxOf(headers, 'home_team_name'),
      away_team_name: idxOf(headers, 'away_team_name'),
      ft_home: idxOf(headers, 'ft_home'),
      ft_away: idxOf(headers, 'ft_away'),
      ht_home: idxOf(headers, 'ht_home'),
      ht_away: idxOf(headers, 'ht_away'),
      outcome: idxOf(headers, 'outcome'),

      // formato atual (log): competition_name, date_utc, home_team, away_team, fulltime_home, fulltime_away, halftime_home, halftime_away, match_outcome
      date_utc: idxOf(headers, 'date_utc'),
      home_team: idxOf(headers, 'home_team'),
      away_team: idxOf(headers, 'away_team'),
      fulltime_home: idxOf(headers, 'fulltime_home'),
      fulltime_away: idxOf(headers, 'fulltime_away'),
      halftime_home: idxOf(headers, 'halftime_home'),
      halftime_away: idxOf(headers, 'halftime_away'),
      match_outcome: idxOf(headers, 'match_outcome'),

      match_id: idxOf(headers, 'match_id'),
    };

    const dateIdx = c.utc_date >= 0 ? c.utc_date : c.date_utc;
    const homeIdx = c.home_team_name >= 0 ? c.home_team_name : c.home_team;
    const awayIdx = c.away_team_name >= 0 ? c.away_team_name : c.away_team;
    if (c.match_id < 0 || dateIdx < 0 || homeIdx < 0 || awayIdx < 0) {
      log('WARN', 'IMPORT', `CSV football: colunas ausentes (headers=${headers.slice(0, 30).join(',')})`);
      return;
    }

    let imported = 0;
    const tx = db.transaction(() => {
      for (let i = 1; i < rows.length; i++) {
        const row = rows[i];
        const mid = row[c.match_id];
        const date = row[dateIdx];
        const home = row[homeIdx];
        const away = row[awayIdx];
        if (!mid || !date || !home || !away) continue;

        const ftHIdx = c.ft_home >= 0 ? c.ft_home : c.fulltime_home;
        const ftAIdx = c.ft_away >= 0 ? c.ft_away : c.fulltime_away;
        const ftH = ftHIdx >= 0 ? parseInt(row[ftHIdx], 10) : null;
        const ftA = ftAIdx >= 0 ? parseInt(row[ftAIdx], 10) : null;
        const score = (Number.isFinite(ftH) && Number.isFinite(ftA)) ? `${ftH}-${ftA}` : '';

        let winner = 'Draw';
        if (Number.isFinite(ftH) && Number.isFinite(ftA)) {
          if (ftH > ftA) winner = home;
          else if (ftA > ftH) winner = away;
        } else {
          const outIdx = c.outcome >= 0 ? c.outcome : c.match_outcome;
          const out = outIdx >= 0 ? String(row[outIdx] || '').toUpperCase() : '';
          if (out === 'H') winner = home;
          else if (out === 'A') winner = away;
          else winner = 'Draw';
        }

        const league = (c.competition_name >= 0 ? String(row[c.competition_name] || '').trim() : '') || 'Dataset';
        const matchId = `fd_${String(mid).trim()}`;
        const resolvedAt = String(date).replace('T', ' ').slice(0, 19); // "YYYY-MM-DD HH:MM:SS"
        stmts.upsertMatchResultWithDate.run(matchId, 'football', String(home), String(away), String(winner), score, league, resolvedAt);
        try { stmts.insertMatchResultSource.run(matchId, 'football', 'dataset_csv_kaggle', String(home), String(away), String(winner), score); } catch (_) {}
        imported++;
      }
    });
    tx();

    stmts.upsertDatasetImport.run(key, 'tarekmasryo/Football-Matches-Results-2024-25-Dataset', imported);
    log('INFO', 'IMPORT', `CSV football importado: ${imported} jogos (key=${key})`);
  } catch (e) {
    log('WARN', 'IMPORT', `CSV football import falhou: ${e.message}`);
  }
}

async function importTennisSackmannCsvForYear(year, tour) {
  const isWta = tour === 'wta';
  let urlCsv = isWta
    ? `https://raw.githubusercontent.com/JeffSackmann/tennis_wta/master/wta_matches_${year}.csv`
    : `https://raw.githubusercontent.com/JeffSackmann/tennis_atp/master/atp_matches_${year}.csv`;
  if (!isWta && process.env.TENNIS_MATCHES_CSV_URL) {
    const yOverride = parseInt(process.env.TENNIS_DATASET_YEAR || String(year), 10);
    if (year === yOverride) urlCsv = process.env.TENNIS_MATCHES_CSV_URL;
  }
  const key = `tennis_csv:${tour}:${year}:${urlCsv}`;
  if (stmts.getDatasetImport.get(key)) return;

  try {
    const r = await cachedHttpGet(urlCsv, { provider: 'tennis_dataset', ttlMs: 24 * 60 * 60 * 1000 }).catch(() => null);
    if (!r || r.status !== 200) {
      if (r?.status === 404) {
        log('INFO', 'IMPORT', `CSV tennis ${tour} ${year}: ainda não disponível no GitHub (404) — use ESPN sync`);
      } else {
        log('WARN', 'IMPORT', `CSV tennis ${tour} ${year}: HTTP ${r?.status || 'fail'}`);
      }
      return;
    }
    const rows = parseCsvRows(String(r.body || ''));
    if (!rows.length || rows.length < 2) { log('WARN', 'IMPORT', `CSV tennis ${tour} ${year}: vazio`); return; }

    const headers = rows[0];
    const c = {
      tourney_id: idxOf(headers, 'tourney_id'),
      tourney_name: idxOf(headers, 'tourney_name'),
      surface: idxOf(headers, 'surface'),
      tourney_level: idxOf(headers, 'tourney_level'),
      tourney_date: idxOf(headers, 'tourney_date'),
      match_num: idxOf(headers, 'match_num'),
      winner_name: idxOf(headers, 'winner_name'),
      loser_name: idxOf(headers, 'loser_name'),
      score: idxOf(headers, 'score'),
    };
    if (c.winner_name < 0 || c.loser_name < 0 || c.tourney_date < 0) {
      log('WARN', 'IMPORT', `CSV tennis ${tour} ${year}: colunas ausentes (headers=${headers.slice(0, 30).join(',')})`);
      return;
    }

    const tourLabel = isWta ? 'WTA' : 'ATP';
    const idPrefix = isWta ? 'tw_' : 'ta_';
    let imported = 0;
    const tx = db.transaction(() => {
      for (let i = 1; i < rows.length; i++) {
        const row = rows[i];
        const w = row[c.winner_name];
        const l = row[c.loser_name];
        const d = row[c.tourney_date];
        if (!w || !l || !d) continue;
        const score = (c.score >= 0 ? String(row[c.score] || '').trim() : '');
        const tourneyName = (c.tourney_name >= 0 ? String(row[c.tourney_name] || '').trim() : '') || tourLabel;
        const surface = (c.surface >= 0 ? String(row[c.surface] || '').trim() : '') || '';
        const level = (c.tourney_level >= 0 ? String(row[c.tourney_level] || '').trim() : '') || '';
        const league = `${tourLabel} ${tourneyName}${surface ? ` (${surface})` : ''}${level ? ` [${level}]` : ''}`;

        const tid = (c.tourney_id >= 0 ? String(row[c.tourney_id] || '').trim() : '');
        const mnum = (c.match_num >= 0 ? String(row[c.match_num] || '').trim() : '');
        const matchIdRaw = [tid || `Y${year}`, d, mnum || String(i)].filter(Boolean).join('_');
        const matchId = `${idPrefix}${matchIdRaw}`.slice(0, 128);

        const resolvedAt = (String(d).length === 8)
          ? `${String(d).slice(0, 4)}-${String(d).slice(4, 6)}-${String(d).slice(6, 8)} 00:00:00`
          : `${String(d).slice(0, 10)} 00:00:00`;

        // 2026-05-07 (audit #50): canonical alphabetic pair pra Sackmann tennis.
        // Antes gravava team1=winner team2=loser ("winner-first") — ESPN tennis
        // grava positional (t1=comps[0]) → 2 convenções na mesma tabela. Downstream
        // já é convention-agnostic (usa coluna winner pra identificar vencedor),
        // mas alfabético deterministic remove inconsistência pra novos rows
        // Sackmann. OLD rows ficam winner-first (sem migração — drift mínimo
        // pq Sackmann é fonte histórica, settlement usa ESPN/SofaScore).
        const wStr = String(w), lStr = String(l);
        const [p1, p2] = wStr.toLowerCase() < lStr.toLowerCase() ? [wStr, lStr] : [lStr, wStr];
        stmts.upsertMatchResultWithDate.run(matchId, 'tennis', p1, p2, wStr, score, league, resolvedAt);
        // Mig 109 (FASE 1 dual-source): log source pra reconcile cron detectar mismatches
        try { stmts.insertMatchResultSource.run(matchId, 'tennis', 'sackmann', p1, p2, wStr, score); } catch (_) {}
        imported++;
      }
    });
    tx();

    stmts.upsertDatasetImport.run(key, `JeffSackmann/tennis_${tour}`, imported);
    log('INFO', 'IMPORT', `CSV tennis ${tour} ${year}: ${imported} jogos`);
  } catch (e) {
    log('WARN', 'IMPORT', `CSV tennis ${tour} ${year} falhou: ${e.message}`);
  }
}

async function importTennisMatchesCsvOnce() {
  const enabled = (process.env.TENNIS_DATASET_IMPORT ?? 'true') !== 'false';
  if (!enabled) return;
  const importWta = (process.env.TENNIS_IMPORT_WTA ?? 'true') !== 'false';
  const y0 = new Date().getFullYear();
  let years;
  const rawYears = (process.env.TENNIS_DATASET_YEARS || '').trim();
  if (rawYears) {
    years = [...new Set(rawYears.split(',').map(s => parseInt(s.trim(), 10)).filter(n => Number.isFinite(n) && n >= 1990 && n <= y0 + 1))];
  } else {
    // Sackmann publica ~ano anterior; 2025/2026 costumam 404 até existir no GitHub
    years = [y0 - 2, y0 - 1, y0].filter(y => y >= 1990);
  }
  for (const year of years) {
    await importTennisSackmannCsvForYear(year, 'atp');
    if (importWta) await importTennisSackmannCsvForYear(year, 'wta');
  }
}

// ── Import opcional: dados gol.gg (CSV) ──
// Usa CSV gerado por scrapers externos (ex: PandaTobi/League-of-Legends-ESports-Data)
// Objetivo: seed/merge em pro_champ_stats quando sync PandaScore estiver vazio
function parseCsvLoose(text) {
  const rows = [];
  let i = 0;
  let field = '';
  let row = [];
  let inQuotes = false;
  while (i < text.length) {
    const ch = text[i];
    if (inQuotes) {
      if (ch === '"') {
        const next = text[i + 1];
        if (next === '"') { field += '"'; i += 2; continue; }
        inQuotes = false;
        i++;
        continue;
      }
      field += ch;
      i++;
      continue;
    }
    if (ch === '"') { inQuotes = true; i++; continue; }
    if (ch === ',') { row.push(field); field = ''; i++; continue; }
    if (ch === '\r') { i++; continue; }
    if (ch === '\n') {
      row.push(field);
      rows.push(row);
      row = [];
      field = '';
      i++;
      continue;
    }
    field += ch;
    i++;
  }
  if (field.length || row.length) {
    row.push(field);
    rows.push(row);
  }
  return rows;
}

function normHeader(h) {
  return String(h || '').trim().toLowerCase().replace(/\s+/g, '_');
}

function importGolGgCsvToProChampStats(csvPath) {
  try {
    if (!csvPath) return { ok: false, reason: 'no_path' };
    const abs = path.isAbsolute(csvPath) ? csvPath : path.resolve(csvPath);
    if (!fs.existsSync(abs)) return { ok: false, reason: 'not_found', path: abs };

    const mode = (process.env.GOLGG_IMPORT_MODE || 'seed').toLowerCase(); // seed|merge
    const champCount = db.prepare('SELECT COUNT(*) as cnt FROM pro_champ_stats').get();
    if (mode === 'seed' && (champCount?.cnt || 0) > 0) return { ok: false, reason: 'already_has_data', cnt: champCount.cnt };

    const raw = fs.readFileSync(abs, 'utf8');
    const rows = parseCsvLoose(raw);
    if (!rows.length) return { ok: false, reason: 'empty_csv' };

    const headers = rows[0].map(normHeader);
    const idx = (name) => headers.indexOf(name);
    const colChampion = idx('champion') >= 0 ? idx('champion') : idx('champ') >= 0 ? idx('champ') : idx('champion_name');
    const colRole = idx('role') >= 0 ? idx('role') : idx('position') >= 0 ? idx('position') : idx('lane');
    const colWins = idx('wins') >= 0 ? idx('wins') : idx('win') >= 0 ? idx('win') : -1;
    const colTotal = idx('total') >= 0 ? idx('total') : idx('games') >= 0 ? idx('games') : idx('matches');
    const colPatch = idx('patch');

    if (colChampion < 0 || colRole < 0 || colWins < 0 || colTotal < 0) {
      return { ok: false, reason: 'missing_columns', headers: headers.slice(0, 50) };
    }

    let imported = 0;
    const patchVal = process.env.LOL_PATCH || (process.env.LOL_PATCH_META || '').slice(0, 16) || null;
    const tx = db.transaction(() => {
      for (let r = 1; r < rows.length; r++) {
        const row = rows[r];
        const champion = String(row[colChampion] || '').trim();
        const roleRaw = String(row[colRole] || '').trim().toLowerCase();
        const wins = parseInt(String(row[colWins] || '0').trim(), 10);
        const total = parseInt(String(row[colTotal] || '0').trim(), 10);
        if (!champion || !roleRaw || !Number.isFinite(wins) || !Number.isFinite(total) || total <= 0) continue;
        const role = roleRaw.replace('bot', 'bottom').replace('adc', 'bottom').replace('sup', 'support');
        const patch = (colPatch >= 0 ? String(row[colPatch] || '').trim() : '') || patchVal || null;
        stmts.addChampStat.run(champion, role, wins, total, patch);
        imported++;
      }
    });
    tx();

    log('INFO', 'BOOT', `gol.gg CSV import: ${imported} linha(s) para pro_champ_stats (${abs})`);
    return { ok: true, imported, path: abs };
  } catch(e) {
    log('WARN', 'BOOT', `gol.gg CSV import falhou: ${e.message}`);
    return { ok: false, reason: e.message };
  }
}

try {
  const csvPath = process.env.GOLGG_CSV_PATH || process.env.GOLGG_PATH || '';
  if (csvPath) importGolGgCsvToProChampStats(csvPath);
} catch(_) {}

