// 2026-05-19 audit P0-2: helper centralizado pra cap body POST endpoints.
// Antes pattern inline replicado 17× (let body = ''; req.on('data', d => body += d))
// sem cap → atacante POST 500MB → OOM Railway 512MB → SIGKILL. /record-tip
// + 4 endpoints destructive/financial já tinham inline cap (commits 9cd741c
// + c5a6135). Helper consolida pattern, facilita aplicar nos demais 12 sites.
//
// Uso: _readPostBody(req, res, (body) => { ... existing logic ... })
//      _readPostBody(req, res, async (body) => { ... }, customMax)
// body=null indica overflow (helper já respondeu com 413). Caller deve return.
function _readPostBody(req, res, cb, maxBytes) {
  const _max = Number.isFinite(maxBytes) ? maxBytes
    : parseInt(process.env.POST_MAX_BODY_BYTES || '65536', 10) || 65536;
  let body = ''; let overflow = false;
  req.on('data', d => {
    if (overflow) return;
    body += d;
    if (body.length > _max) {
      overflow = true; body = '';
      try { sendJson(res, { ok: false, error: 'body_too_large', max_bytes: _max }, 413); } catch (_) {}
      try { cb(null); } catch (_) {} // notify caller que já respondemos
    }
  });
  req.on('end', () => { if (!overflow) { try { cb(body); } catch (e) {
    try { log('WARN', 'POST-BODY', `cb error: ${e.message}`); } catch (_) {}
  } } });
  req.on('error', () => { if (!overflow) { try { cb(null); } catch (_) {} } });
}

// SEC P0 2026-05-27: rate-limit helper para /*-result family.
// Mitiga DoS via raffle pattern matchIds que drena Riot/PandaScore/Sofa quota.
// 60 req/min per-IP é generoso pra uso normal (bot interno polls 1-2 req/min/endpoint).
function _matchResultRateLimit(req, res, p) {
  const ip = String(req.socket?.remoteAddress || '');
  if (!ip) return true;
  global._matchResultRateMap = global._matchResultRateMap || new Map();
  const now = Date.now();
  const cur = global._matchResultRateMap.get(ip) || { count: 0, windowStart: now };
  if (now - cur.windowStart > 60_000) { cur.count = 0; cur.windowStart = now; }
  cur.count++;
  global._matchResultRateMap.set(ip, cur);
  if (cur.count > 60) { sendJson(res, { ok: false, error: 'rate_limit', endpoint: p }, 429); return false; }
  if (global._matchResultRateMap.size > 500) {
    for (const [k, v] of global._matchResultRateMap) if (now - v.windowStart > 5*60_000) global._matchResultRateMap.delete(k);
  }
  return true;
}

async function theOddsGet(theOddsUrl) {
  return await theOddsQueue.enqueue(`theodds:${theOddsUrl}`, async () => {
    const ttlMsRaw = parseInt(process.env.HTTP_CACHE_THEODDS_TTL_MS || '', 10);
    const ttlMs = Number.isFinite(ttlMsRaw) ? ttlMsRaw : 15 * 60 * 1000; // cache de 15 minutos por default!
    return await cachedHttpGet(theOddsUrl, { provider: 'theodds', ttlMs }).catch(() => ({ status: 500, body: '[]' }));
  });
}

function isWtaTennisOddsKey(k) {
  return /(^|_)wta(_|$)/i.test(String(k));
}

/** Chaves tennis_* (ATP + WTA). Com all=true a API devolve torneios fora de temporada — WTA deixa de sumir. */
async function fetchTheOddsTennisSportKeys() {
  if (!THE_ODDS_API_KEY) return [];
  const useAll = (process.env.TENNIS_ODDS_SPORTS_ALL ?? 'true') !== 'false';
  const q = useAll ? `apiKey=${THE_ODDS_API_KEY}&all=true` : `apiKey=${THE_ODDS_API_KEY}`;
  const sportsR = await theOddsGet(`https://api.the-odds-api.com/v4/sports/?${q}`);
  const allSports = safeParse(sportsR.body, []);
  const tennisSports = allSports.filter(s => s && typeof s.key === 'string' && s.key.startsWith('tennis_'));
  tennisSports.sort((a, b) => {
    const ai = a.active === false ? 1 : 0;
    const bi = b.active === false ? 1 : 0;
    if (ai !== bi) return ai - bi;
    return String(a.key).localeCompare(String(b.key));
  });
  return tennisSports.map(s => s.key);
}

/** Prioriza WTA (mínimo configurável) e completa com ATP em round-robin. */
function pickBalancedTennisKeys(tennisKeys, maxKeys) {
  const wtaKeys = tennisKeys.filter(isWtaTennisOddsKey);
  const atpKeys = tennisKeys.filter(k => !isWtaTennisOddsKey(k));
  const cap = Math.min(Math.max(2, maxKeys || 10), tennisKeys.length);
  const minWtaCfg = parseInt(process.env.TENNIS_MIN_WTA_KEYS || '5', 10);
  const minWta = Math.min(Math.max(0, Number.isFinite(minWtaCfg) ? minWtaCfg : 5), wtaKeys.length, cap);
  const allowedKeys = [];
  let wi = 0;
  let ai = 0;
  for (; wi < minWta; wi++) allowedKeys.push(wtaKeys[wi]);
  while (allowedKeys.length < cap && (ai < atpKeys.length || wi < wtaKeys.length)) {
    if (ai < atpKeys.length) allowedKeys.push(atpKeys[ai++]);
    if (allowedKeys.length >= cap) break;
    if (wi < wtaKeys.length) allowedKeys.push(wtaKeys[wi++]);
  }
  return { allowedKeys, wtaKeys, atpKeys };
}

