// ── Pinnacle — Dota 2 (esports) ──
// sportId=12 (E-Sports) filtrado por league.name contendo "Dota 2"
// Descarta matchups de kills e handicap (só queremos match winner série)
let _dotaPinnacleCache = { data: [], ts: 0 };
// TTL adaptativo: 45s quando há live (odds vivas mexem rápido), 3min idle.
const DOTA_PINNACLE_TTL_LIVE = 45 * 1000;
const DOTA_PINNACLE_TTL_IDLE = 3 * 60 * 1000;
// Throttle do log "0 partidas": só loga quando count/leaguesSeen muda OU passou ≥10min.
let _dotaPinnacleLogState = { count: -1, leaguesSeen: -1, ts: 0 };
const DOTA_PINNACLE_LOG_THROTTLE_MS = 10 * 60 * 1000;

async function getPinnacleDotaMatches() {
  if (process.env.PINNACLE_DOTA === 'false') return [];
  const hasLiveCached = _dotaPinnacleCache.data.some(m => m.status === 'live');
  const ttl = hasLiveCached ? DOTA_PINNACLE_TTL_LIVE : DOTA_PINNACLE_TTL_IDLE;
  if (_dotaPinnacleCache.data.length && (Date.now() - _dotaPinnacleCache.ts) < ttl) {
    return _dotaPinnacleCache.data;
  }
  try {
    // Diagnóstico: conta ligas vistas e amostra ligas descartadas quando filtro zera resultado.
    // Motivo: Pinnacle ocasionalmente muda o nome da liga ("Dota 2" → "DotA2" / "Dota2") e o
    // filtro estrito `.includes('dota 2')` descartava tudo silenciosamente.
    let leaguesSeen = 0;
    const leaguesSkipped = new Set();
    const rows = await pinnacle.fetchSportMatchOdds(12, (m) => {
      const name = String(m?.league?.name || '').toLowerCase();
      leaguesSeen++;
      // Regex relaxado: "dota 2", "dota2", "dota  2", "dota - 2", etc.
      if (!/\bdota\s*-?\s*2?\b/i.test(name)) {
        if (leaguesSkipped.size < 10 && name) leaguesSkipped.add(name.slice(0, 40));
        return false;
      }
      const p1 = String(m?.participants?.[0]?.name || '');
      const p2 = String(m?.participants?.[1]?.name || '');
      // Descarta: (Kills) mercado de total kills + handicap de map ("X 0, Y 2 vs X 1, Y 2")
      if (/\(kills\)/i.test(p1) || /\(kills\)/i.test(p2)) return false;
      if (/\d+,\s*\w+\s+\d+/.test(p1) || /\d+,\s*\w+\s+\d+/.test(p2)) return false;
      return true;
    });
    const matches = rows.map(r => ({
      id: `pin_${r.id}`,
      team1: r.team1,
      team2: r.team2,
      league: r.league,
      status: r.status === 'live' ? 'live' : 'upcoming',
      time: r.startTime,
      odds: { t1: String(r.oddsT1), t2: String(r.oddsT2), bookmaker: 'Pinnacle' }
    }));
    _dotaPinnacleCache = { data: matches, ts: Date.now() };
    const _stateChanged = matches.length !== _dotaPinnacleLogState.count
                       || leaguesSeen !== _dotaPinnacleLogState.leaguesSeen;
    const _throttleExpired = (Date.now() - _dotaPinnacleLogState.ts) >= DOTA_PINNACLE_LOG_THROTTLE_MS;
    if (_stateChanged || _throttleExpired) {
      if (matches.length === 0 && leaguesSeen > 0) {
        const sample = [...leaguesSkipped].slice(0, 5).join(', ');
        log('INFO', 'ODDS', `Pinnacle Dota 2: 0 (de ${leaguesSeen} esports markets; ligas vistas: ${sample || '-'})`);
      } else {
        log('INFO', 'ODDS', `Pinnacle Dota 2: ${matches.length} partidas cacheadas`);
      }
      _dotaPinnacleLogState = { count: matches.length, leaguesSeen, ts: Date.now() };
    }
    try { require('./lib/feed-heartbeat').markFeedSuccess('pinnacle', 'dota2', matches.length); } catch (_) {}
    return matches;
  } catch (e) {
    log('ERROR', 'ODDS', `Pinnacle Dota 2: ${e.message}`);
    try { require('./lib/feed-heartbeat').markFeedFailure('pinnacle', 'dota2', e.message); } catch (_) {}
    return [];
  }
}

// ── Pinnacle — Mixed Martial Arts (sportId=22) ──
// 2026-05-08: wirado pra MMA shadow re-evaluation. Memory cita lift modelo
// 4-6% marginal (audit-modelos 2026-04-21), mas Pinnacle UFC tem ~22 fights
// ATM e modelo + ESPN MMA + Sherdog backfill já existem. Worth shadow test
// de 30d antes de re-ativar real dispatch.
let _mmaPinnacleCache = { data: [], ts: 0 };
const MMA_PINNACLE_TTL_IDLE = 10 * 60 * 1000;
const MMA_PINNACLE_TTL_LIVE = 60 * 1000;

async function getPinnacleMmaMatches() {
  if (process.env.PINNACLE_MMA === 'false') return [];
  const hadLive = _mmaPinnacleCache.data.some(m => m.status === 'live');
  const ttl = hadLive ? MMA_PINNACLE_TTL_LIVE : MMA_PINNACLE_TTL_IDLE;
  if (_mmaPinnacleCache.data.length && (Date.now() - _mmaPinnacleCache.ts) < ttl) {
    return _mmaPinnacleCache.data;
  }
  try {
    const rows = await pinnacle.fetchSportMatchOdds(22, (m) => {
      const lg = String(m?.league?.name || '');
      const p1 = String(m?.participants?.[0]?.name || '');
      const p2 = String(m?.participants?.[1]?.name || '');
      // Filtra prop bets (rounds, methods, OUs específicos) — só moneyline H2H
      if (/\((rounds|method|inside|outside|distance|decision|ko|sub|kos|tkos)\)/i.test(p1 + p2)) return false;
      // UFC + Bellator + ONE + PFL principalmente; descarta promotions amadoras
      if (!/\b(ufc|bellator|one championship|pfl|cage warriors|ksw|rizin|invicta)\b/i.test(lg)) return false;
      return true;
    });
    const _fetchedAt = Date.now();
    const matches = rows.map(r => ({
      id: `pin_mma_${r.id}`,
      team1: r.team1, team2: r.team2,
      league: r.league,
      sport_key: 'mma',
      game: 'mma',
      status: r.status === 'live' ? 'live' : 'upcoming',
      time: r.startTime,
      odds: { t1: String(r.oddsT1), t2: String(r.oddsT2), bookmaker: 'Pinnacle', _fetchedAt },
      _source: 'pinnacle',
    }));
    _mmaPinnacleCache = { data: matches, ts: Date.now() };
    // 2026-05-15: breakdown per-org pra audit de unlock non-UFC.
    // Quando Bellator/PFL/ONE/etc card week, deve aparecer >0 aqui — confirma
    // que regex (server.js:3411) está deixando passar e que Pinnacle cobre.
    const _orgKeys = ['ufc', 'bellator', 'pfl', 'one championship', 'cage warriors', 'ksw', 'rizin', 'invicta'];
    const _orgCounts = matches.reduce((acc, m) => {
      const lg = String(m.league || '').toLowerCase();
      const k = _orgKeys.find(o => lg.includes(o)) || 'other';
      acc[k] = (acc[k] || 0) + 1;
      return acc;
    }, {});
    const _orgStr = Object.entries(_orgCounts).filter(([_,v]) => v > 0).map(([k,v]) => `${k}:${v}`).join(' ');
    log('INFO', 'ODDS', `Pinnacle MMA: ${matches.length} lutas cacheadas (${_orgStr || 'empty'})`);
    try { require('./lib/feed-heartbeat').markFeedSuccess('pinnacle', 'mma', matches.length); } catch (_) {}
    return matches;
  } catch (e) {
    log('ERROR', 'ODDS', `Pinnacle MMA: ${e.message}`);
    try { require('./lib/feed-heartbeat').markFeedFailure('pinnacle', 'mma', e.message); } catch (_) {}
    return [];
  }
}

