// ── Pinnacle — Soccer (sportId=29) ──
// Filtro de ligas: top-tier + Brasileirão + 2nd-tier europeias maduras (volume sob controle).
// Pinnacle soccer é alto volume (200+ jogos/dia globais); filtro evita estourar quota.
let _footballPinnacleCache = { data: [], ts: 0 };
const FOOTBALL_PINNACLE_TTL_IDLE = 10 * 60 * 1000;
const FOOTBALL_PINNACLE_TTL_LIVE = 60 * 1000;

const FOOTBALL_PINNACLE_LEAGUE_PATTERNS = [
  // Top tier (volume sharp)
  /premier league/i, /la liga/i, /\bserie a\b/i, /bundesliga/i, /ligue 1/i,
  /eredivisie/i, /primeira liga/i, /\bsuper lig\b/i,
  // Continental
  /champions league/i, /europa league/i, /conference league/i,
  // South America
  /brasileir/i, /libertadores/i, /sudamericana/i, /argentina.*primera/i,
  // 2nd tier Europe (volume razoável)
  /championship/i, /league one/i, /league two/i, /2\.\s*bundesliga/i,
  /serie b/i, /segunda/i, /ligue 2/i, /eerste divisie/i,
  // Major cups
  /\bfa cup\b/i, /\bdfb pokal\b/i, /\bcoppa italia\b/i, /\bcopa del rey\b/i,
];

async function getPinnacleFootballMatches() {
  if (process.env.PINNACLE_FOOTBALL !== 'true') return [];
  const hadLive = _footballPinnacleCache.data.some(m => m.status === 'live');
  const ttl = hadLive ? FOOTBALL_PINNACLE_TTL_LIVE : FOOTBALL_PINNACLE_TTL_IDLE;
  if (_footballPinnacleCache.data.length && (Date.now() - _footballPinnacleCache.ts) < ttl) {
    return _footballPinnacleCache.data;
  }
  try {
    // 2026-05-15: explicit diagnostic — audit log mostrou "0 partidas" 50× sem
    // distinção entre "Pinnacle Guest sem soccer" vs "filter rejeita tudo".
    // Quebrar fetchSportMatchOdds em 2 etapas pra log raw + filtered counts.
    const allMatchups = await pinnacle.listSportMatchups(29);
    const filterFn = (m) => {
      const name = String(m?.league?.name || '');
      if (!FOOTBALL_PINNACLE_LEAGUE_PATTERNS.some(rx => rx.test(name))) return false;
      const p1 = String(m?.participants?.[0]?.name || '');
      const p2 = String(m?.participants?.[1]?.name || '');
      if (/\((corners|cards|bookings|fouls|shots)\)/i.test(p1 + p2)) return false;
      return true;
    };
    const filteredMatchups = allMatchups.filter(filterFn);
    const rows = [];
    for (const m of filteredMatchups) {
      const row = await pinnacle.extractMoneyline(m);
      if (row) rows.push(row);
    }
    const _fetchedAt = Date.now();
    const matches = rows.map(r => ({
      id: `pin_fb_${r.id}`,
      team1: r.team1, team2: r.team2,
      league: r.league,
      sport_key: 'soccer',
      status: r.status === 'live' ? 'live' : 'upcoming',
      time: r.startTime,
      odds: { t1: String(r.oddsT1), t2: String(r.oddsT2), bookmaker: 'Pinnacle', _fetchedAt }
    }));
    _footballPinnacleCache = { data: matches, ts: Date.now() };
    // 2026-05-15: log level adaptativo. raw=0 sustained = Pinnacle Guest API
    // sem soccer (Case A, confirmed via audit logs.1778869825145 — 50× WARN
    // em 30min com raw=0). DEBUG quando raw=0 (não actionable, esperado).
    // WARN apenas quando raw>0 mas filter rejeita tudo (Case B: actionable —
    // filter regex mismatch). INFO quando matches retornados (Case OK).
    if (matches.length === 0) {
      if (allMatchups.length === 0) {
        log('DEBUG', 'ODDS', `Pinnacle Football: 0 partidas (Guest API sem soccer — esperado)`);
      } else {
        // Sample league names from raw pra debug filter mismatch
        const sampleLeagues = [...new Set(allMatchups.slice(0, 30).map(m => m?.league?.name).filter(Boolean))].slice(0, 5);
        log('WARN', 'ODDS', `Pinnacle Football: 0 partidas (raw=${allMatchups.length} filtered=${filteredMatchups.length} with_odds=0)${sampleLeagues.length ? ` | sample_leagues=${sampleLeagues.join(' | ')}` : ''}`);
      }
    } else {
      log('INFO', 'ODDS', `Pinnacle Football: ${matches.length} partidas cacheadas (raw=${allMatchups.length} filtered=${filteredMatchups.length})`);
    }
    return matches;
  } catch (e) {
    log('ERROR', 'ODDS', `Pinnacle Football: ${e.message}`);
    return [];
  }
}

// ── Pinnacle — Counter-Strike 2 (sportId=12 E-Sports, league filter "Counter-Strike"|"CS2"|"CS:GO") ──
let _csPinnacleCache = { data: [], ts: 0 };
const CS_PINNACLE_TTL = 3 * 60 * 1000;

async function getPinnacleCsMatches() {
  if (_csPinnacleCache.data.length && (Date.now() - _csPinnacleCache.ts) < CS_PINNACLE_TTL) {
    return _csPinnacleCache.data;
  }
  try {
    const rows = await pinnacle.fetchSportMatchOdds(12, (m) => {
      // 2026-05-17 FIX: filter dupla check (audit log 17/05 "CS 0 odds 15+ ciclos
      // persistente"). Pinnacle nomeia ligas como "IEM Dallas 2026" / "BLAST
      // Premier Fall Groups" SEM "counter-strike" no nome — segunda regex
      // rejeitava todas. Pinnacle sportId=12 já expõe `league.group` que
      // discrimina ('Counter-Strike' / 'League of Legends' / 'Dota 2'). Usar
      // group field como sinal primário evita LoL leak quando torneios genéricos.
      const group = String(m?.league?.group || '').toLowerCase();
      const name = String(m?.league?.name || '').toLowerCase();
      const isCsGroup = /counter.?strike|cs\s*2|cs:?go/.test(group);
      const isCsName = /(counter-?strike|cs\s*2|cs:?go)/.test(name);
      const isCsTournament = /(esea|esl|blast|iem|major|katowice|cologne|riyadh|ewc|cct|epl)/i.test(name);
      // Accept se: group confirma CS OR name explicit CS OR (tournament-only AND group nao-LoL).
      if (!isCsGroup && !isCsName) {
        if (!isCsTournament) return false;
        // Tournament name sem "cs" e sem group field — só aceita se group ausente
        // (Pinnacle inconsistente) OR group nao é League of Legends/Dota 2/Valorant.
        if (group && /league of legends|dota|valorant|starcraft|overwatch|rocket league|king of glory/.test(group)) return false;
      }
      const p1 = String(m?.participants?.[0]?.name || '');
      const p2 = String(m?.participants?.[1]?.name || '');
      // Descarta mercados de map/round/handicap
      if (/\((kills|rounds|maps|handicap)\)/i.test(p1) || /\((kills|rounds|maps|handicap)\)/i.test(p2)) return false;
      if (/\d+,\s*\w+\s+\d+/.test(p1) || /\d+,\s*\w+\s+\d+/.test(p2)) return false;
      return true;
    });
    const matches = rows.map(r => ({
      id: `pin_cs_${r.id}`,
      team1: r.team1,
      team2: r.team2,
      league: r.league,
      status: r.status === 'live' ? 'live' : 'upcoming',
      time: r.startTime,
      odds: { t1: String(r.oddsT1), t2: String(r.oddsT2), bookmaker: 'Pinnacle' }
    }));
    _csPinnacleCache = { data: matches, ts: Date.now() };
    log('INFO', 'ODDS', `Pinnacle CS2: ${matches.length} partidas cacheadas`);
    try { require('./lib/feed-heartbeat').markFeedSuccess('pinnacle', 'cs', matches.length); } catch (_) {}
    return matches;
  } catch (e) {
    log('ERROR', 'ODDS', `Pinnacle CS2: ${e.message}`);
    try { require('./lib/feed-heartbeat').markFeedFailure('pinnacle', 'cs', e.message); } catch (_) {}
    return [];
  }
}

// ── PandaScore Dota 2 ──
let _pandaDotaCache = { data: [], ts: 0 };
// TTL dual: 30s quando há live (score pode mudar), 90s quando idle
const PANDA_DOTA_CACHE_TTL_LIVE = parseInt(process.env.PANDA_DOTA_CACHE_TTL_LIVE_MS || '30000', 10);
const PANDA_DOTA_CACHE_TTL_IDLE = parseInt(process.env.PANDA_DOTA_CACHE_TTL_IDLE_MS || '90000', 10);

async function getPandaScoreDotaMatches() {
  if (!PANDASCORE_TOKEN || PANDASCORE_TOKEN === 'your-pandascore-token') return [];
  if (_pandaIsBackedOff('dota2')) return [];
  const hadLive = _pandaDotaCache.data.some(m => m.status === 'live');
  const ttl = hadLive ? PANDA_DOTA_CACHE_TTL_LIVE : PANDA_DOTA_CACHE_TTL_IDLE;
  if (_pandaDotaCache.data.length && (Date.now() - _pandaDotaCache.ts) < ttl) return _pandaDotaCache.data;
  try {
    const [runningRaw, upcomingRaw] = await Promise.all([
      _pandaGet('/dota2/matches/running?per_page=20'),
      _pandaGet('/dota2/matches/upcoming?per_page=30&sort=begin_at')
    ]);
    // 2026-05-18 (EXT-2 P5): shared _psParseMatchList detecta 429 + backoff.
    const running = _psParseMatchList(runningRaw, 'dota2', 'PandaScore Dota 2 running');
    const upcoming = _psParseMatchList(upcomingRaw, 'dota2', 'PandaScore Dota 2 upcoming');

    const mapDota = (m, status) => {
      const t1 = m.opponents?.[0]?.opponent, t2 = m.opponents?.[1]?.opponent;
      const n1 = t1?.name || 'TBD', n2 = t2?.name || 'TBD';
      if (n1 === 'TBD' && n2 === 'TBD') return null;
      const leagueName = m.league?.name || m.serie?.full_name || 'Dota 2';
      const format = m.number_of_games > 1 ? `Bo${m.number_of_games}` : 'Bo1';
      let s1 = 0, s2 = 0;
      if (Array.isArray(m.games)) {
        for (const g of m.games) {
          if (!g.winner) continue;
          if (g.winner.id === t1?.id) s1++;
          else if (g.winner.id === t2?.id) s2++;
        }
      }
      return {
        id: `dota2_ps_${m.id}`,
        game: 'dota2',
        league: leagueName,
        leagueSlug: m.league?.slug || '',
        team1: n1, team2: n2,
        score1: s1, score2: s2,
        status,
        time: m.begin_at || '',
        format,
        winner: m.winner?.name || null,
        _psId: String(m.id),
        _source: 'pandascore'
      };
    };

    const live = running.map(m => mapDota(m, 'live')).filter(Boolean);
    const next = upcoming
      .filter(m => {
        const t = new Date(m.begin_at).getTime();
        return !isNaN(t) && t < Date.now() + 7 * 24 * 3600 * 1000;
      })
      .map(m => mapDota(m, 'upcoming')).filter(Boolean);

    const result = [...live, ...next];
    if (result.length) log('INFO', 'DOTA2', `PandaScore: ${result.length} partidas (${live.length} live)`);
    try { require('./lib/feed-heartbeat').markFeedSuccess('pandascore', 'dota2', result.length); } catch (_) {}
    _pandaDotaCache = { data: result, ts: Date.now() };
    return result;
  } catch(e) {
    log('WARN', 'DOTA2', 'getPandaScoreDotaMatches: ' + e.message);
    try { require('./lib/feed-heartbeat').markFeedFailure('pandascore', 'dota2', e.message); } catch (_) {}
    return _pandaDotaCache.data;
  }
}

