let _valorantPinnacleCache = { data: [], ts: 0 };
const VALORANT_PINNACLE_TTL = 3 * 60 * 1000;

async function getPinnacleValorantMatches() {
  if (_valorantPinnacleCache.data.length && (Date.now() - _valorantPinnacleCache.ts) < VALORANT_PINNACLE_TTL) {
    return _valorantPinnacleCache.data;
  }
  try {
    const rows = await pinnacle.fetchSportMatchOdds(12, (m) => {
      // 2026-05-17 FIX (mesma class do CS filter): aceitar group field como
      // discriminator quando name não contém "valorant" literal. VCT regional
      // (Americas/EMEA/Pacific) e Champions Tour podem não ter "valorant" no name.
      const group = String(m?.league?.group || '').toLowerCase();
      const name = String(m?.league?.name || '').toLowerCase();
      const isValGroup = group === 'valorant';
      const isValName = name.includes('valorant');
      const isValTournament = /(vct|champions tour|game changers|challengers|masters|red bull home ground)/i.test(name);
      // SEC P0-F 2026-05-27 fix: blacklist CS/LoL/Dota leagues via NAME (não só group).
      // Confirmed live: "CS2 - CCT Europe Challengers" entrava como Valorant via wildcard 'challengers'.
      if (/^cs(?:2|:go)?\b|counter.?strike|league of legends|dota|starcraft|overwatch|rocket league/i.test(name)) return false;
      if (!isValGroup && !isValName) {
        if (!isValTournament) return false;
        if (group && /counter.?strike|league of legends|dota|starcraft|overwatch|rocket league/.test(group)) return false;
      }
      const p1 = String(m?.participants?.[0]?.name || '');
      const p2 = String(m?.participants?.[1]?.name || '');
      if (/\((kills|rounds|maps|handicap)\)/i.test(p1) || /\((kills|rounds|maps|handicap)\)/i.test(p2)) return false;
      if (/\d+,\s*\w+\s+\d+/.test(p1) || /\d+,\s*\w+\s+\d+/.test(p2)) return false;
      return true;
    });
    const matches = rows.map(r => ({
      id: `pin_valorant_${r.id}`,
      team1: r.team1,
      team2: r.team2,
      league: r.league,
      status: r.status === 'live' ? 'live' : 'upcoming',
      time: r.startTime,
      odds: { t1: String(r.oddsT1), t2: String(r.oddsT2), bookmaker: 'Pinnacle' }
    }));
    _valorantPinnacleCache = { data: matches, ts: Date.now() };
    log('INFO', 'ODDS', `Pinnacle Valorant: ${matches.length} partidas cacheadas`);
    return matches;
  } catch (e) {
    log('ERROR', 'ODDS', `Pinnacle Valorant: ${e.message}`);
    return [];
  }
}

